// COMPANY LIST v7
// - Board APIs first (no array-splitting)
// - Per-company ATS (JSON objects, no splitting)
// - HTML/JSON-LD career pages (test batch)
// - Lever + RemoteOK LAST (bare array => n8n splits => handled by v7 parser)

const sources = [

  // FREE GLOBAL JOB BOARDS (safe -- return JSON objects)
  { ats: 'remotive',  slug: 'remotive',  company: 'Remotive Board' },
  { ats: 'himalayas', slug: 'himalayas', company: 'Himalayas' },
  { ats: 'arbeitnow', slug: 'arbeitnow', company: 'Arbeitnow' },
  { ats: 'jobicy',    slug: 'india',     company: 'Jobicy India' },
  { ats: 'jobicy',    slug: 'usa',       company: 'Jobicy USA Remote' },

  // GREENHOUSE -- returns {jobs:[]} object, no splitting
  { ats: 'greenhouse', slug: 'gitlab',       company: 'GitLab' },
  { ats: 'greenhouse', slug: 'razorpay',     company: 'Razorpay' },
  { ats: 'greenhouse', slug: 'postman',      company: 'Postman' },
  { ats: 'greenhouse', slug: 'browserstack', company: 'BrowserStack' },
  { ats: 'greenhouse', slug: 'moengage',     company: 'MoEngage' },
  { ats: 'greenhouse', slug: 'hasura',       company: 'Hasura' },
  { ats: 'greenhouse', slug: 'notion',       company: 'Notion' },
  { ats: 'greenhouse', slug: 'groww',        company: 'Groww' },
  { ats: 'greenhouse', slug: 'druva',        company: 'Druva' },
  { ats: 'greenhouse', slug: 'cloudflare',   company: 'Cloudflare' },
  { ats: 'greenhouse', slug: 'rippling',     company: 'Rippling' },
  { ats: 'greenhouse', slug: 'gusto',        company: 'Gusto' },
  { ats: 'greenhouse', slug: 'twilio',       company: 'Twilio' },
  { ats: 'greenhouse', slug: 'brex',         company: 'Brex' },
  { ats: 'greenhouse', slug: 'grammarly',    company: 'Grammarly' },
  { ats: 'greenhouse', slug: 'zapier',       company: 'Zapier' },

  // SMARTRECRUITERS -- returns {content:[]} object
  { ats: 'smartrecruiters', slug: 'Meesho',     company: 'Meesho' },
  { ats: 'smartrecruiters', slug: 'Freshworks', company: 'Freshworks' },
  { ats: 'smartrecruiters', slug: 'PhonePe',    company: 'PhonePe' },

  // ASHBY -- returns {jobs:[]} object
  { ats: 'ashby', slug: 'linear',   company: 'Linear' },
  { ats: 'ashby', slug: 'clerk',    company: 'Clerk.dev' },
  { ats: 'ashby', slug: 'cal',      company: 'Cal.com' },
  { ats: 'ashby', slug: 'supabase', company: 'Supabase' },
  { ats: 'ashby', slug: 'resend',   company: 'Resend' },
  { ats: 'ashby', slug: 'posthog',  company: 'PostHog' },
  { ats: 'ashby', slug: 'raycast',  company: 'Raycast' },
  { ats: 'ashby', slug: 'vercel',   company: 'Vercel' },

  // WORKABLE -- returns {results:[]} object
  { ats: 'workable', slug: 'zepto',      company: 'Zepto' },
  { ats: 'workable', slug: 'cred',       company: 'CRED' },
  { ats: 'workable', slug: 'shiprocket', company: 'Shiprocket' },

  // REPLACED HTML LISTINGS WITH VERIFIED ENDPOINTS
  { ats: 'greenhouse', slug: 'shopify',   company: 'Shopify' },
  { ats: 'greenhouse', slug: 'chargebee', company: 'Chargebee' },
  { ats: 'greenhouse', slug: 'sprinklr',  company: 'Sprinklr' },

  // LEVER -- bare array response => n8n SPLITS items
  // Placed LAST so index-split only affects entries at the tail.
  // v7 parser detects company from hostedUrl automatically.
  { ats: 'lever', slug: 'gohighlevel', company: 'GoHighLevel' },
  { ats: 'lever', slug: 'remote',      company: 'Remote.com' },
  { ats: 'lever', slug: 'delhivery',   company: 'Delhivery' },
  { ats: 'lever', slug: 'netlify',     company: 'Netlify' },
  { ats: 'lever', slug: 'figma',       company: 'Figma' },
  { ats: 'lever', slug: 'loom',        company: 'Loom' },

  // REMOTEOK -- bare array response => n8n SPLITS items
  // Placed last. Parser reads .company field from each split item.
  { ats: 'remoteok', slug: 'remoteok', company: 'Remote OK' },

];

console.log('Company List v7: ' + sources.length + ' sources');
return sources.map(c => ({ json: c }));

// Builds API URL + headers for ALL sources in one pass.
// Each source gets its own item => HTTP Request calls each one.
// v2: Adds pagination for Remotive (higher limit), SmartRecruiters (offset),
//     and Himalayas (page param) to capture all available jobs.

const H = { 'Accept': 'application/json', 'User-Agent': 'Mozilla/5.0 (compatible; JobBot/4.2)' };
const results = [];

for (const entry of $input.all()) {
  const { ats, slug, company, url: customUrl } = entry.json;
  if (!ats || !slug) continue;

  let headers = H;
  if (ats === 'remoteok') {
    headers = { ...H, 'Accept': 'application/json', 'Cache-Control': 'no-cache' };
  } else if (ats === 'html_json_ld') {
    headers = { 'User-Agent': 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/120.0.0.0 Safari/537.36', 'Accept': 'text/html' };
  }
  const route = ats === 'html_json_ld' ? 'html' : 'api';
  const base  = { ...entry.json, _headers: headers, _route: route };

  // Paginated sources
  // SmartRecruiters: offset-based pagination (5 pages x 100 = 500 jobs max)
  if (ats === 'smartrecruiters') {
    for (let offset = 0; offset < 500; offset += 100) {
      results.push({ json: { ...base, _url: 'https://api.smartrecruiters.com/v1/companies/' + slug + '/postings?status=PUBLIC&limit=100&offset=' + offset } });
    }
    continue;
  }

  // Himalayas: page-based pagination (10 pages x 50 = 500 jobs max)
  if (ats === 'himalayas') {
    for (let page = 1; page <= 10; page++) {
      results.push({ json: { ...base, _url: 'https://himalayas.app/jobs/api?limit=50&page=' + page } });
    }
    continue;
  }

  // Non-paginated sources (single URL)
  const urlMap = {
    remotive:     'https://remotive.com/api/remote-jobs?limit=500',
    remoteok:     'https://remoteok.com/api',
    arbeitnow:    'https://www.arbeitnow.com/api/job-board-api',
    jobicy:       slug === 'india'
                    ? 'https://jobicy.com/api/v2/remote-jobs?count=100&geo=india'
                    : 'https://jobicy.com/api/v2/remote-jobs?count=100&geo=usa',
    lever:        'https://api.lever.co/v0/postings/' + slug + '?mode=json&limit=250',
    greenhouse:   'https://boards-api.greenhouse.io/v1/boards/' + slug + '/jobs?content=true',
    workable:     'https://apply.workable.com/api/v1/widget/accounts/' + slug,
    ashby:        'https://api.ashbyhq.com/posting-api/job-board/' + slug,
    html_json_ld: customUrl
  };

  const url = urlMap[ats];
  if (!url) { console.log('Unknown ATS: ' + ats); continue; }

  results.push({ json: { ...base, _url: url } });
}

console.log('Prepare Request v2: ' + results.length + ' API calls queued (includes pagination)');
return results;

// PARSE + ENRICH + FILTER

// tiny helpers
const str = v => {
  if (v == null) return '';
  if (typeof v === 'object') return v.label || v.name || v.id || '';
  return String(v);
};

// ISO country map
const ISO2 = {IN:'India',US:'United States',GB:'United Kingdom',AU:'Australia',CA:'Canada',DE:'Germany',SG:'Singapore',AE:'UAE',FR:'France',NL:'Netherlands',PK:'Pakistan',PH:'Philippines',NG:'Nigeria',KE:'Kenya',ZA:'South Africa',BR:'Brazil',JP:'Japan',KR:'South Korea',IE:'Ireland',PL:'Poland',NZ:'New Zealand',PT:'Portugal',IT:'Italy',ES:'Spain',UA:'Ukraine'};
const CNAMES = {india:'India',bharat:'India','united states':'United States',usa:'United States','united kingdom':'United Kingdom',australia:'Australia',canada:'Canada',germany:'Germany',singapore:'Singapore',uae:'UAE',dubai:'UAE',netherlands:'Netherlands',france:'France',pakistan:'Pakistan',philippines:'Philippines',nigeria:'Nigeria',kenya:'Kenya','south africa':'South Africa',brazil:'Brazil',japan:'Japan','south korea':'South Korea',ireland:'Ireland',poland:'Poland','new zealand':'New Zealand',portugal:'Portugal',italy:'Italy',spain:'Spain',ukraine:'Ukraine'};
const INDIA_CITIES = new Set(['bengaluru','bangalore','mumbai','bombay','delhi','new delhi','hyderabad','pune','chennai','madras','kolkata','calcutta','noida','gurugram','gurgaon','ahmedabad','jaipur','kochi','chandigarh','coimbatore','indore','nagpur','bhopal','lucknow','surat','vadodara','trivandrum','vizag','mangalore','mysuru','nashik']);

function parseSalary(raw) {
  if (!raw && raw !== 0) return '';
  if (typeof raw === 'string') {
    const s = raw.trim();
    if (!s || s === '0' || s === 'null') return '';
    if (/^\d/.test(s)) {
      const nums = s.match(/\d+(?:[,.]\d+)*/g);
      if (nums && nums.length >= 2) {
        const [lo, hi] = nums.map(n => Number(n.replace(/,/g,'')));
        const sym = /INR/.test(s) ? 'INR ' : /GBP/.test(s) ? 'GBP ' : /EUR/.test(s) ? 'EUR ' : '$';
        const per = /year|annual/i.test(s) ? '/yr' : /month/i.test(s) ? '/mo' : /hour/i.test(s) ? '/hr' : '';
        return sym + fmt(lo) + '--' + fmt(hi) + per;
      }
    }
    return s.slice(0, 200);
  }
  if (typeof raw === 'number') {
    return raw > 0 ? '$' + fmt(raw) : '';
  }
  if (typeof raw === 'object') {
    const inner = raw.value || raw;
    let min = inner.minValue || inner.min || inner.minimum || inner.floor || 0;
    let max = inner.maxValue || inner.max || inner.maximum || inner.ceiling || 0;
    const currency = str(raw.currency || inner.currency || raw.salaryCurrency || 'USD');
    const interval = str(raw.unitText || inner.unitText || inner.interval || raw.salaryFrequency || '');
    const sym = currency === 'INR' ? 'INR ' : currency === 'GBP' ? 'GBP ' : currency === 'EUR' ? 'EUR ' : '$';
    const perStr = interval ? ' /' + interval.toLowerCase().replace(/^per\s*/i,'').replace('year','yr').replace('month','mo').replace('hour','hr') : '';
    if (!min && !max) return '';
    const parts = [];
    if (min) parts.push(sym + fmt(min));
    if (max && max !== min) parts.push(sym + fmt(max));
    return parts.join('--') + perStr + ' ' + currency;
  }
  return '';
}

function fmt(n) {
  n = Number(n);
  if (n >= 10000000) return (n/10000000).toFixed(1).replace(/\.0$/,'') + 'Cr';
  if (n >= 100000)   return (n/100000).toFixed(1).replace(/\.0$/,'') + 'L';
  if (n >= 1000)     return (n/1000).toFixed(0) + 'k';
  return String(Math.round(n));
}

function parseDate(raw) {
  if (!raw) return '';
  let d;
  if (typeof raw === 'number') {
    d = new Date(raw > 1e10 ? raw : raw * 1000);
  } else if (typeof raw === 'string') {
    const s = raw.trim();
    if (!s) return '';
    d = new Date(s);
  } else if (raw instanceof Date) {
    d = raw;
  }
  if (!d || isNaN(d.getTime())) return '';
  return d.toISOString().slice(0, 10);
}

function getCountry(rawLoc, rawCC) {
  const cc = str(rawCC);
  if (cc) {
    const up = cc.trim().toUpperCase();
    if (ISO2[up]) return ISO2[up];
    const lo = cc.trim().toLowerCase();
    if (CNAMES[lo]) return CNAMES[lo];
    if (cc.trim().length > 2) return cc.trim();
  }
  const loc = str(rawLoc);
  if (!loc) return 'Unknown';
  const l = loc.toLowerCase();
  if (/^(remote|remote worldwide|anywhere|global|worldwide)$/i.test(l.trim())) return 'Global';
  if ([...INDIA_CITIES].some(c => l.includes(c))) return 'India';
  if (/\busa\b|united states/.test(l)) return 'United States';
  for (const [a,c] of Object.entries(CNAMES)) if (l.includes(a)) return c;
  const last = loc.split(/[,|\/]/).pop()?.trim().toUpperCase();
  if (last && ISO2[last]) return ISO2[last];
  return 'Unknown';
}

function getWorkMode(title, rawLoc, explicit) {
  const ex = str(explicit).toLowerCase().replace(/[^a-z]/g,'');
  if (ex === 'remote')  return 'Remote';
  if (ex === 'hybrid')  return 'Hybrid';
  if (ex === 'onsite' || ex === 'inoffice') return 'Onsite';
  const t = (str(title) + ' ' + str(rawLoc)).toLowerCase();
  if (/\bremote\b|\bwfh\b|work from home|distributed|\banywhere\b/.test(t)) return 'Remote';
  if (/\bhybrid\b/.test(t)) return 'Hybrid';
  return 'Onsite';
}

function cleanLoc(rawLoc, mode) {
  const loc = str(rawLoc);
  if (!loc) return mode === 'Remote' ? 'Remote' : 'Not specified';
  const FIX = {bangalore:'Bengaluru',bombay:'Mumbai',madras:'Chennai',calcutta:'Kolkata',gurgaon:'Gurugram',cochin:'Kochi'};
  let l = loc.replace(/[,\s,]+/g, ', ').trim();
  for (const [o,n] of Object.entries(FIX)) l = l.replace(new RegExp('\\b'+o+'\\b','gi'), n);
  return l || 'Not specified';
}

function normType(raw) {
  const t = str(raw).toLowerCase().replace(/[^a-z]/g,'');
  if (/intern/.test(t))              return 'Internship';
  if (/contract|contractor|freelance/.test(t)) return 'Contract';
  if (/parttime/.test(t))            return 'Part-time';
  return 'Full-time';
}

function cleanDesc(html) {
  const h = str(html);
  if (!h) return '';
  return h
    .replace(/<br\s*\/?>/gi, '\n')
    .replace(/<\/?(p|li|div|h[1-6])[^>]*>/gi, '\n')
    .replace(/<[^>]+>/g, '')
    .replace(/&amp;/g,'&').replace(/&lt;/g,'<').replace(/&gt;/g,'>').replace(/&nbsp;/g,' ').replace(/&#\d+;/g,'')
    .replace(/\n{3,}/g, '\n\n').trim().slice(0, 2000);
}

function makeHash(ats, company, title, location) {
  const s = [ats, company, title, location].map(x => (x||'').toLowerCase().trim()).join('|');
  let h1 = 0, h2 = 0;
  for (let i = 0; i < s.length; i++) {
    h1 = Math.imul(31, h1) + s.charCodeAt(i) | 0;
    h2 = Math.imul(37, h2) + s.charCodeAt(i) | 0;
  }
  return Math.abs(h1).toString(36) + Math.abs(h2).toString(36);
}

const ALLOWED_DOMAINS = [
  'business analyst', 'business analysis', 'business systems analyst',
  'product manager', 'product management', 'associate pm', 'senior pm',
  'head of product', 'vp of product', 'director of product',
  'data analyst', 'data analysis', 'analytics analyst',
  'business intelligence', 'bi analyst', 'reporting analyst',
  'product designer', 'ux designer', 'ui designer', 'ux/ui', 'ui/ux',
  'product design', 'interaction designer', 'visual designer',
  'user experience', 'user interface designer',
  'full stack', 'fullstack', 'full-stack', 'software engineer',
  'software developer', 'backend engineer', 'frontend engineer',
  'backend developer', 'frontend developer', 'web developer',
  'sales', 'account executive', 'account manager',
  'business development', 'sdr', 'bdr',
  'sales development', 'sales manager', 'revenue'
];

function isTitleAllowed(title) {
  const t = title.toLowerCase();
  return ALLOWED_DOMAINS.some(kw => t.includes(kw));
}

function shouldKeep(country, work_mode) {
  if (country === 'India') return true;
  if (work_mode === 'Remote') return true;
  return false;
}

function buildOutput(rawJobs, ats, company) {
  const seen = new Set(), out = [];
  for (const j of rawJobs) {
    if (!j.title || j.title.length < 2) continue;
    if (!isTitleAllowed(j.title)) continue;
    const work_mode       = getWorkMode(j.title, j.rawLoc, j.mode);
    const country         = getCountry(j.rawLoc, j.rawCC);
    if (!shouldKeep(country, work_mode)) continue;
    const location        = cleanLoc(j.rawLoc, work_mode);
    const employment_type = normType(j.type);
    const job_hash        = makeHash(ats, company, j.title, location);
    if (seen.has(job_hash)) continue;
    seen.add(job_hash);
    const salaryStr  = parseSalary(j.salary);
    const postedDate = parseDate(j.posted);
    out.push({ json: {
      job_title:       j.title.trim(),
      company,
      location,
      country,
      work_mode,
      employment_type,
      apply_url:       str(j.url),
      ats_type:        ats,
      job_hash,
      description:     cleanDesc(j.desc),
      salary:          salaryStr,
      posted_date:     postedDate,
      status:          'active'
    }});
  }
  return out;
}

function detectATS(resp) {
  if (typeof resp === 'string' && resp.includes('<html')) return 'html_json_ld';
  if (resp && resp.data && typeof resp.data === 'string' && resp.data.includes('<html')) return 'html_json_ld';
  if (!resp || typeof resp !== 'object') return null;
  if ('text' in resp && 'hostedUrl' in resp && String(resp.hostedUrl).includes('lever.co')) return 'lever';
  if ('position' in resp && ('apply_url' in resp || 'url' in resp) && 'company' in resp) return 'remoteok';
  if (Array.isArray(resp)) {
    const f = resp.find(j => j && typeof j === 'object');
    if (!f) return null;
    if ('position' in f && 'company' in f) return 'remoteok';
    if ('text' in f && 'categories' in f && 'hostedUrl' in f) return 'lever';
    return null;
  }
  if (resp.jobs && Array.isArray(resp.jobs)) {
    const f = resp.jobs[0] || {};
    if ('candidate_required_location' in f) return 'remotive';
    if ('jobTitle' in f) return 'jobicy';
    if ('absolute_url' in f) return 'greenhouse';
    if ('jobUrl' in f || 'workplaceType' in f) return 'ashby';
    return 'ashby';
  }
  if (resp.data && Array.isArray(resp.data))    return 'arbeitnow';
  if (resp.content && Array.isArray(resp.content)) return 'smartrecruiters';
  if (resp.results && Array.isArray(resp.results)) return 'workable';
  return null;
}

function getCompanyFromResp(resp, ats, cfgCompany, cfgSlug) {
  if (ats === 'remotive')  return 'Remotive Board';
  if (ats === 'himalayas') return 'Himalayas';
  if (ats === 'arbeitnow') return 'Arbeitnow';
  if (ats === 'jobicy')    return cfgSlug === 'india' ? 'Jobicy India' : 'Jobicy USA Remote';
  if (ats === 'remoteok') {
    const src = Array.isArray(resp) ? resp[0] : resp;
    const co  = src && src.company;
    return co && co !== '0' && co.length > 1 ? co : 'Remote OK';
  }
  if (ats === 'lever') {
    const src = Array.isArray(resp) ? resp[0] : resp;
    if (src && src.hostedUrl) {
      const m = src.hostedUrl.match(/lever\.co\/([^/?#]+)/);
      if (m) return m[1].replace(/-/g,' ').replace(/\b\w/g, c => c.toUpperCase());
    }
    return cfgCompany || cfgSlug || 'Lever';
  }
  if (ats === 'greenhouse') {
    const f = resp.jobs && resp.jobs[0];
    if (f && f.company_name && f.company_name.length > 1) return f.company_name;
    if (f && f.absolute_url) { const m = f.absolute_url.match(/greenhouse\.io\/([^/?#]+)/); if (m) return m[1]; }
    return cfgCompany || cfgSlug || 'Greenhouse';
  }
  if (ats === 'ashby') {
    const f = resp.jobs && resp.jobs[0];
    if (f && f.jobUrl) { const m = f.jobUrl.match(/ashbyhq\.com\/([^/?#]+)/); if (m) return m[1].replace(/-/g,' ').replace(/\b\w/g, c => c.toUpperCase()); }
    return cfgCompany || cfgSlug || 'Ashby';
  }
  return cfgCompany || cfgSlug || ats;
}

// Main Loop
const httpItems = $input.all();
const cfgAll    = $('Prepare Request').all();
const allJobs   = [];

console.log('Parse v10: ' + httpItems.length + ' HTTP items | ' + cfgAll.length + ' cfg entries');

for (let i = 0; i < httpItems.length; i++) {
  const resp = httpItems[i].json;

  let cfgIndex = Math.min(i, cfgAll.length - 1);
  const paired = httpItems[i].pairedItem;
  if (paired != null) {
    if (typeof paired === 'object' && !Array.isArray(paired) && typeof paired.item === 'number') {
      cfgIndex = Math.min(paired.item, cfgAll.length - 1);
    } else if (Array.isArray(paired) && paired.length > 0 && typeof paired[0].item === 'number') {
      cfgIndex = Math.min(paired[0].item, cfgAll.length - 1);
    }
  }
  const cfg = cfgAll[cfgIndex] ? cfgAll[cfgIndex].json : {};

  const ats      = detectATS(resp) || str(cfg.ats);
  const cfgSlug  = str(cfg.slug);
  const company  = getCompanyFromResp(resp, ats, str(cfg.company), cfgSlug);
  const htmlStr  = (typeof resp === 'string') ? resp : (resp && typeof resp.data === 'string' ? resp.data : null);

  if (!ats) { console.log('item ' + i + ': cannot detect ATS'); continue; }

  let rawJobs = [];

  switch (ats) {

    case 'html_json_ld': {
      if (!htmlStr) { console.log('[html_json_ld] ' + company + ': no HTML body'); break; }
      let matchCount = 0;
      const regex = /<script[^>]*type=["']application\/ld\+json["'][^>]*>([\s\S]*?)<\/script>/gi;
      let m;
      while ((m = regex.exec(htmlStr)) !== null) {
        try {
          const parsed = JSON.parse(m[1]);
          const items  = Array.isArray(parsed) ? parsed : [parsed];
          for (const item of items) {
            const entities = item['@graph'] || [item];
            for (const ent of entities) {
              if (ent['@type'] !== 'JobPosting') continue;
              matchCount++;
              const rawLocObj = ent.jobLocation
                ? (Array.isArray(ent.jobLocation) ? ent.jobLocation[0] : ent.jobLocation)
                : null;
              let locStr = 'Remote';
              let rawCC  = '';
              if (rawLocObj && rawLocObj.address) {
                locStr = str(rawLocObj.address.addressLocality)
                      || str(rawLocObj.address.addressRegion)
                      || str(rawLocObj.address.addressCountry)
                      || 'Remote';
                rawCC  = str(rawLocObj.address.addressCountry);
              }
              const isRemote = str(ent.jobLocationType).toLowerCase().includes('remote')
                            || str(ent.description).toLowerCase().includes('remote');
              let salary = '';
              if (ent.baseSalary) {
                salary = parseSalary(ent.baseSalary);
              } else if (ent.estimatedSalary) {
                salary = parseSalary(ent.estimatedSalary);
              }
              const posted = parseDate(ent.datePosted || ent.dateCreated || '');
              rawJobs.push({
                title:  str(ent.title || ent.name).trim(),
                rawLoc: isRemote ? 'Remote' : locStr,
                rawCC,
                type:   str(ent.employmentType) || 'Full-time',
                mode:   isRemote ? 'Remote' : null,
                url:    str(ent.url) || str(cfg.url) || '',
                desc:   str(ent.description),
                salary,
                posted
              });
            }
          }
        } catch(e) { /* malformed JSON-LD */ }
      }
      console.log('[html_json_ld] ' + company + ': ' + matchCount + ' JobPosting entries');
      break;
    }

    case 'remotive':
      rawJobs = (resp.jobs || []).map(j => ({
        title:  str(j.title).trim(),
        rawLoc: str(j.candidate_required_location),
        rawCC:  '',
        type:   str(j.job_type),
        mode:   null,
        url:    str(j.url),
        desc:   str(j.description),
        salary: parseSalary(j.salary),
        posted: parseDate(j.publication_date)
      }));
      break;

    case 'remoteok': {
      const list = Array.isArray(resp)
        ? resp.filter(j => j && j.position)
        : (resp && resp.position ? [resp] : []);
      rawJobs = list.map(j => ({
        title:  str(j.position).trim(),
        rawLoc: str(j.location) || 'Worldwide',
        rawCC:  '',
        type:   'Full-time',
        mode:   'Remote',
        url:    str(j.apply_url) || str(j.url),
        desc:   str(j.description),
        salary: (j.salary_min || j.salary_max)
                  ? parseSalary({ min: j.salary_min, max: j.salary_max, currency: 'USD', interval: 'YEAR' })
                  : '',
        posted: parseDate(j.date || j.epoch)
      }));
      break;
    }

    case 'himalayas': {
      const jobs = resp.jobs || resp.data || (Array.isArray(resp) ? resp : []);
      rawJobs = jobs.map(j => ({
        title:  str(j.title).trim(),
        rawLoc: str(j.location) || str(j.regions) || 'Remote',
        rawCC:  '',
        type:   str(j.jobType) || str(j.type),
        mode:   'Remote',
        url:    str(j.applyUrl) || str(j.url),
        desc:   str(j.description),
        salary: j.salary
                  ? parseSalary(j.salary)
                  : (j.minSalary || j.maxSalary)
                    ? parseSalary({ min: j.minSalary, max: j.maxSalary, currency: j.currency || 'USD', interval: 'YEAR' })
                    : '',
        posted: parseDate(j.createdAt || j.publishedAt || j.postedAt)
      }));
      break;
    }

    case 'arbeitnow':
      rawJobs = (resp.data || []).map(j => ({
        title:  str(j.title).trim(),
        rawLoc: str(j.location),
        rawCC:  '',
        type:   Array.isArray(j.job_types) ? str(j.job_types[0]) : 'Full-time',
        mode:   j.remote ? 'Remote' : null,
        url:    str(j.url),
        desc:   str(j.description),
        salary: parseSalary(j.salary || ''),
        posted: parseDate(j.created_at || j.published_at)
      }));
      break;

    case 'jobicy':
      rawJobs = (resp.jobs || []).map(j => ({
        title:  str(j.jobTitle).trim(),
        rawLoc: str(j.jobGeo) || str(j.jobRegion) || 'Remote',
        rawCC:  '',
        type:   str(j.jobType),
        mode:   'Remote',
        url:    str(j.url),
        desc:   str(j.jobExcerpt),
        salary: (j.annualSalaryMin || j.annualSalaryMax)
                  ? parseSalary({ min: j.annualSalaryMin, max: j.annualSalaryMax, currency: j.salaryCurrency || 'USD', interval: 'YEAR' })
                  : '',
        posted: parseDate(j.pubDate || j.postDate)
      }));
      break;

    case 'lever': {
      const list = Array.isArray(resp) ? resp : (resp && resp.text ? [resp] : []);
      rawJobs = list.map(j => ({
        title:  str(j.text).trim(),
        rawLoc: str(j.categories && j.categories.location),
        rawCC:  '',
        type:   str(j.categories && j.categories.commitment),
        mode:   null,
        url:    str(j.hostedUrl) || str(j.applyUrl),
        desc:   str(j.descriptionPlain),
        salary: (j.salaryRange && (j.salaryRange.min || j.salaryRange.max))
                  ? parseSalary({
                      min:      j.salaryRange.min,
                      max:      j.salaryRange.max,
                      currency: j.salaryRange.currency || 'USD',
                      interval: j.salaryRange.interval || 'YEAR'
                    })
                  : '',
        posted: parseDate(j.createdAt)
      }));
      break;
    }

    case 'greenhouse':
      rawJobs = (resp.jobs || []).map(j => ({
        title:  str(j.title).trim(),
        rawLoc: str(j.location && j.location.name),
        rawCC:  '',
        type:   '',
        mode:   null,
        url:    str(j.absolute_url) || ('https://boards.greenhouse.io/' + cfgSlug),
        desc:   str(j.content),
        salary: '',
        posted: parseDate(j.updated_at || j.created_at)
      }));
      break;

    case 'workable':
      rawJobs = (resp.results || []).map(j => {
        const loc = j.location || {};
        const city = str(loc.city), cc = str(loc.country_code) || str(loc.country);
        const rem  = loc.telecommuting || j.remote || false;
        return {
          title:  str(j.title).trim(),
          rawLoc: rem ? ('Remote' + (city ? ', '+city : '')) : [city, cc].filter(Boolean).join(', '),
          rawCC:  cc,
          type:   str(j.type),
          mode:   rem ? 'Remote' : null,
          url:    str(j.url) || ('https://apply.workable.com/' + cfgSlug),
          desc:   str(j.description),
          salary: '',
          posted: parseDate(j.published_on || j.created_at)
        };
      });
      break;

    case 'smartrecruiters':
      rawJobs = (resp.content || []).map(j => {
        const loc  = j.location || {};
        const city = str(loc.city), cc = str(loc.country);
        const rem  = loc.remote || false;
        const comp = j.compensation;
        return {
          title:  str(j.name).trim(),
          rawLoc: rem ? ('Remote' + (city ? ', '+city : '')) : [city, cc].filter(Boolean).join(', '),
          rawCC:  cc,
          type:   str(j.typeOfEmployment && j.typeOfEmployment.label),
          mode:   rem ? 'Remote' : null,
          url:    str(j.ref) || ('https://careers.smartrecruiters.com/' + cfgSlug),
          desc:   str(j.jobAdText),
          salary: comp
                    ? parseSalary({ min: comp.min, max: comp.max, currency: comp.currency, interval: comp.remuneration })
                    : '',
          posted: parseDate(j.releasedDate || j.createdOn)
        };
      });
      break;

    case 'ashby':
      rawJobs = (resp.jobs || []).map(j => {
        const addr = (j.address && j.address.postalAddress) || {};
        return {
          title:  str(j.title).trim(),
          rawLoc: str(j.location) || [str(addr.addressLocality), str(addr.addressRegion), str(addr.addressCountry)].filter(Boolean).join(', '),
          rawCC:  str(addr.addressCountry),
          type:   str(j.employmentType),
          mode:   str(j.workplaceType) || (j.isRemote ? 'Remote' : null),
          url:    str(j.jobUrl) || str(j.applyUrl) || ('https://jobs.ashbyhq.com/' + cfgSlug),
          desc:   str(j.descriptionHtml) || str(j.descriptionPlain),
          salary: j.compensationTierSummary
                    ? parseSalary(str(j.compensationTierSummary))
                    : (j.salary ? parseSalary(j.salary) : ''),
          posted: parseDate(j.publishedDate || j.createdAt)
        };
      });
      break;

    default:
      console.log('Unknown ATS: ' + ats);
      continue;
  }

  console.log('[' + ats + '] ' + company + ': ' + rawJobs.length + ' raw jobs');
  const kept = buildOutput(rawJobs, ats, company);
  console.log('[' + ats + '] ' + company + ': ' + kept.length + ' kept after filter');
  for (const job of kept) allJobs.push(job);
}

console.log('Parse v10 total: ' + allJobs.length + ' jobs');
return allJobs.length > 0 ? allJobs : [{ json: { _empty: true } }];
